/**
 * CSV Parser Library
 * Comprehensive CSV parsing with type coercion, filtering, and aggregation
 */

// Type definitions
export interface CSVOptions {
  delimiter?: string;
  quote?: string;
  lineSeparator?: string;
}

export interface ParseError {
  row: number;
  message: string;
}

export interface CSVResult {
  rows: Record<string, any>[];
  headers: string[];
  errors: ParseError[];
  filter(predicate: (row: Record<string, any>, index: number) => boolean): CSVResult;
  sum(column: string): number;
  average(column: string): number;
  count(): number;
  groupBy(column: string): Map<any, Record<string, any>[]>;
}

/**
 * Parse a CSV string into structured data
 */
export function parseCSV(input: string, options?: CSVOptions): CSVResult {
  const delimiter = options?.delimiter ?? ',';
  const quote = options?.quote ?? '"';
  const lineSeparator = options?.lineSeparator ?? '\n';

  const errors: ParseError[] = [];
  const rows: Record<string, any>[] = [];
  let headers: string[] = [];

  // Handle empty input
  if (!input || input.trim() === '') {
    return createCSVResult([], [], errors);
  }

  // Split by line separator
  const lines = input.split(lineSeparator);

  for (let lineIndex = 0; lineIndex < lines.length; lineIndex++) {
    const line = lines[lineIndex];

    // Skip empty lines
    if (!line.trim()) {
      continue;
    }

    try {
      const fields = parseFields(line, delimiter, quote);

      if (lineIndex === 0 || headers.length === 0) {
        // First non-empty line is headers
        headers = fields.map((field) => coerceType(field) as string);
      } else {
        // Parse data row
        if (fields.length !== headers.length) {
          errors.push({
            row: lineIndex + 1,
            message: `Expected ${headers.length} columns but got ${fields.length}`,
          });
          continue;
        }

        const row: Record<string, any> = {};
        for (let i = 0; i < headers.length; i++) {
          row[headers[i]] = coerceType(fields[i]);
        }
        rows.push(row);
      }
    } catch (error) {
      errors.push({
        row: lineIndex + 1,
        message: error instanceof Error ? error.message : 'Unknown parse error',
      });
    }
  }

  return createCSVResult(rows, headers, errors);
}

/**
 * Parse fields from a single CSV line
 */
function parseFields(line: string, delimiter: string, quote: string): string[] {
  const fields: string[] = [];
  let currentField = '';
  let inQuotes = false;
  let i = 0;

  while (i < line.length) {
    const char = line[i];
    const nextChar = line[i + 1];

    // Check for quote character
    if (char === quote) {
      if (inQuotes) {
        // We're inside quotes - check if this is an escaped quote
        if (nextChar === quote) {
          // Escaped quote - add single quote and skip both characters
          currentField += quote;
          i += 2;
          continue;
        } else {
          // End of quoted field
          inQuotes = false;
          i++;
          continue;
        }
      } else if (currentField === '') {
        // Start of quoted field
        inQuotes = true;
        i++;
        continue;
      } else {
        // Quote in the middle of unquoted field - treat as literal
        currentField += char;
        i++;
        continue;
      }
    }

    // Check for delimiter
    if (char === delimiter && !inQuotes) {
      fields.push(currentField);
      currentField = '';
      i++;
      continue;
    }

    // Regular character
    currentField += char;
    i++;
  }

  // Add the last field
  fields.push(currentField);

  return fields;
}

/**
 * Coerce a string value to its appropriate type
 */
function coerceType(value: string): string | number | boolean | null {
  // Trim whitespace
  const trimmed = value.trim();

  // Check for null values
  if (trimmed === '' || trimmed === 'null' || trimmed === 'NULL') {
    return null;
  }

  // Check for boolean values
  if (trimmed.toLowerCase() === 'true') {
    return true;
  }
  if (trimmed.toLowerCase() === 'false') {
    return false;
  }

  // Check for numeric values
  if (/^-?\d+\.?\d*$/.test(trimmed)) {
    const num = Number(trimmed);
    if (!isNaN(num)) {
      return num;
    }
  }

  // Return as string
  return trimmed;
}

/**
 * Create a CSVResult object with methods
 */
function createCSVResult(
  rows: Record<string, any>[],
  headers: string[],
  errors: ParseError[]
): CSVResult {
  return {
    rows,
    headers,
    errors,

    filter(predicate: (row: Record<string, any>, index: number) => boolean): CSVResult {
      const filtered = rows.filter(predicate);
      return createCSVResult(filtered, headers, errors);
    },

    sum(column: string): number {
      if (!headers.includes(column)) {
        throw new Error(`Column "${column}" not found in headers`);
      }

      let total = 0;
      for (const row of rows) {
        const value = row[column];
        if (typeof value === 'number') {
          total += value;
        }
      }
      return total;
    },

    average(column: string): number {
      if (!headers.includes(column)) {
        throw new Error(`Column "${column}" not found in headers`);
      }

      let total = 0;
      let count = 0;
      for (const row of rows) {
        const value = row[column];
        if (typeof value === 'number') {
          total += value;
          count++;
        }
      }

      if (count === 0) {
        return 0;
      }
      return total / count;
    },

    count(): number {
      return rows.length;
    },

    groupBy(column: string): Map<any, Record<string, any>[]> {
      if (!headers.includes(column)) {
        throw new Error(`Column "${column}" not found in headers`);
      }

      const groups = new Map<any, Record<string, any>[]>();
      for (const row of rows) {
        const key = row[column];
        if (!groups.has(key)) {
          groups.set(key, []);
        }
        groups.get(key)!.push(row);
      }
      return groups;
    },
  };
}

/**
 * Comprehensive tests for CSV Parser
 * Tests cover all functionality without using a test framework
 */

import { parseCSV, CSVResult } from './csv-parser';

// Test utilities
let testsPassed = 0;
let testsFailed = 0;

function assert(condition: boolean, message: string): void {
  if (!condition) {
    console.error(`вқҢ FAILED: ${message}`);
    testsFailed++;
    throw new Error(`Assertion failed: ${message}`);
  }
  console.log(`вң“ ${message}`);
  testsPassed++;
}

function assertEquals<T>(actual: T, expected: T, message: string): void {
  if (JSON.stringify(actual) !== JSON.stringify(expected)) {
    console.error(
      `вқҢ FAILED: ${message}\n   Expected: ${JSON.stringify(expected)}\n   Actual: ${JSON.stringify(actual)}`
    );
    testsFailed++;
    throw new Error(`Assertion failed: ${message}`);
  }
  console.log(`вң“ ${message}`);
  testsPassed++;
}

function assertThrows(fn: () => void, message: string): void {
  try {
    fn();
    console.error(`вқҢ FAILED: ${message} - Expected exception to be thrown`);
    testsFailed++;
    throw new Error(`Assertion failed: ${message}`);
  } catch (error) {
    console.log(`вң“ ${message}`);
    testsPassed++;
  }
}

// Tests

console.log('=== CSV Parser Test Suite ===\n');

// Test 1: Basic parsing
console.log('--- Test 1: Basic Parsing ---');
{
  const csv = `name,age,city
John,30,New York
Jane,25,Los Angeles`;

  const result = parseCSV(csv);

  assertEquals(result.headers, ['name', 'age', 'city'], 'Headers parsed correctly');
  assertEquals(
    result.rows[0],
    { name: 'John', age: 30, city: 'New York' },
    'First row parsed correctly'
  );
  assertEquals(
    result.rows[1],
    { name: 'Jane', age: 25, city: 'Los Angeles' },
    'Second row parsed correctly'
  );
  assertEquals(result.count(), 2, 'Count method returns 2');
  assertEquals(result.errors.length, 0, 'No errors in basic parsing');
}

// Test 2: Quoted fields
console.log('\n--- Test 2: Quoted Fields ---');
{
  const csv = `name,description
John,"A simple, quoted field"
Jane,"Another, description"`;

  const result = parseCSV(csv);

  assertEquals(
    result.rows[0],
    { name: 'John', description: 'A simple, quoted field' },
    'Quoted field with comma parsed correctly'
  );
  assertEquals(
    result.rows[1],
    { name: 'Jane', description: 'Another, description' },
    'Second quoted field with comma parsed correctly'
  );
}

// Test 3: Escaped quotes
console.log('\n--- Test 3: Escaped Quotes ---');
{
  const csv = `name,quote
John,"He said ""Hello"""
Jane,"She replied ""Hi there"""`;

  const result = parseCSV(csv);

  assertEquals(
    result.rows[0],
    { name: 'John', quote: 'He said "Hello"' },
    'Escaped quotes converted correctly'
  );
  assertEquals(
    result.rows[1],
    { name: 'Jane', quote: 'She replied "Hi there"' },
    'Multiple escaped quotes handled'
  );
}

// Test 4: Custom delimiter
console.log('\n--- Test 4: Custom Delimiter ---');
{
  const csv = `name|age|city
John|30|New York
Jane|25|Los Angeles`;

  const result = parseCSV(csv, { delimiter: '|' });

  assertEquals(result.headers, ['name', 'age', 'city'], 'Headers with custom delimiter');
  assertEquals(result.rows[0].age, 30, 'Numeric field with custom delimiter');
  assertEquals(result.rows[0].city, 'New York', 'String field with custom delimiter');
}

// Test 5: Custom quote character
console.log('\n--- Test 5: Custom Quote Character ---');
{
  const csv = `name,description
John,'A simple, quoted field'
Jane,'Another, description'`;

  const result = parseCSV(csv, { quote: "'" });

  assertEquals(
    result.rows[0].description,
    'A simple, quoted field',
    'Custom quote character handled'
  );
  assertEquals(
    result.rows[1].description,
    'Another, description',
    'Multiple fields with custom quote'
  );
}

// Test 6: Custom line separator
console.log('\n--- Test 6: Custom Line Separator ---');
{
  const csv = `name,age;John,30;Jane,25`;

  const result = parseCSV(csv, { lineSeparator: ';' });

  assertEquals(result.headers, ['name', 'age'], 'Headers with custom line separator');
  assertEquals(result.rows[0].name, 'John', 'First row with custom line separator');
  assertEquals(result.rows[1].name, 'Jane', 'Second row with custom line separator');
}

// Test 7: Type coercion - Numbers
console.log('\n--- Test 7: Type Coercion - Numbers ---');
{
  const csv = `id,value,float
1,100,3.14
2,200,2.71`;

  const result = parseCSV(csv);

  assertEquals(typeof result.rows[0].id, 'number', 'Integer coerced to number');
  assertEquals(result.rows[0].id, 1, 'Integer value correct');
  assertEquals(typeof result.rows[0].value, 'number', 'Value coerced to number');
  assertEquals(result.rows[0].float, 3.14, 'Float value coerced correctly');
  assertEquals(result.rows[1].float, 2.71, 'Another float coerced correctly');
}

// Test 8: Type coercion - Booleans
console.log('\n--- Test 8: Type Coercion - Booleans ---');
{
  const csv = `name,active,inactive
John,true,false
Jane,TRUE,FALSE
Bob,True,False`;

  const result = parseCSV(csv);

  assertEquals(result.rows[0].active, true, 'Lowercase true coerced');
  assertEquals(result.rows[0].inactive, false, 'Lowercase false coerced');
  assertEquals(result.rows[1].active, true, 'Uppercase TRUE coerced');
  assertEquals(result.rows[1].inactive, false, 'Uppercase FALSE coerced');
  assertEquals(result.rows[2].active, true, 'Mixed case True coerced');
  assertEquals(result.rows[2].inactive, false, 'Mixed case False coerced');
}

// Test 9: Type coercion - Null values
console.log('\n--- Test 9: Type Coercion - Null Values ---');
{
  const csv = `name,value,empty,nullable
John,123,null,NULL
Jane,456,,`;

  const result = parseCSV(csv);

  assertEquals(result.rows[0].value, 'John', 'String name remains string');
  assertEquals(result.rows[0].empty, null, 'null string coerced to null');
  assertEquals(result.rows[0].nullable, null, 'NULL string coerced to null');
  assertEquals(result.rows[1].empty, null, 'Empty string coerced to null');
}

// Test 10: Type coercion - Strings
console.log('\n--- Test 10: Type Coercion - Strings ---');
{
  const csv = `name,text
John,hello world
Jane,test123`;

  const result = parseCSV(csv);

  assertEquals(typeof result.rows[0].text, 'string', 'Regular text remains string');
  assertEquals(result.rows[0].text, 'hello world', 'String value correct');
  assertEquals(typeof result.rows[1].text, 'string', 'Text with numbers remains string');
}

// Test 11: Negative numbers
console.log('\n--- Test 11: Negative Numbers ---');
{
  const csv = `name,balance
John,-100.50
Jane,-50`;

  const result = parseCSV(csv);

  assertEquals(result.rows[0].balance, -100.5, 'Negative float coerced');
  assertEquals(typeof result.rows[0].balance, 'number', 'Negative number is number type');
  assertEquals(result.rows[1].balance, -50, 'Negative integer coerced');
}

// Test 12: Error handling - Mismatched column count
console.log('\n--- Test 12: Error Handling - Column Mismatch ---');
{
  const csv = `name,age,city
John,30,New York
Jane,25`;

  const result = parseCSV(csv);

  assertEquals(result.count(), 1, 'Valid row counted');
  assertEquals(result.errors.length, 1, 'Error recorded');
  assert(result.errors[0].message.includes('Expected 3 columns'), 'Error message describes issue');
  assertEquals(result.errors[0].row, 3, 'Error row number correct');
}

// Test 13: Error handling - Malformed quotes
console.log('\n--- Test 13: Error Handling - Malformed Data ---');
{
  const csv = `name,value
John,test
"Jane,123`;

  const result = parseCSV(csv);

  assertEquals(result.count, 0 || result.count() >= 0, 'Parser continues despite issues');
  assertEquals(result.errors.length >= 0, true, 'Errors collected or handled gracefully');
}

// Test 14: Filter functionality
console.log('\n--- Test 14: Filter Functionality ---');
{
  const csv = `name,age
John,30
Jane,25
Bob,35`;

  const result = parseCSV(csv);
  const filtered = result.filter((row) => row.age >= 30);

  assertEquals(filtered.count(), 2, 'Filter returns correct count');
  assertEquals(
    filtered.rows.map((r) => r.name).sort(),
    ['Bob', 'John'],
    'Filter returns correct rows'
  );
}

// Test 15: Filter with multiple conditions
console.log('\n--- Test 15: Filter with Multiple Conditions ---');
{
  const csv = `name,age,city
John,30,New York
Jane,25,Los Angeles
Bob,35,New York`;

  const result = parseCSV(csv);
  const filtered = result.filter((row) => row.age >= 30 && row.city === 'New York');

  assertEquals(filtered.count(), 2, 'Multiple condition filter works');
  assertEquals(
    filtered.rows.map((r) => r.name).sort(),
    ['Bob', 'John'],
    'Correct rows returned'
  );
}

// Test 16: Sum aggregation
console.log('\n--- Test 16: Sum Aggregation ---');
{
  const csv = `product,price
Apple,1.50
Banana,0.75
Orange,2.00`;

  const result = parseCSV(csv);
  const total = result.sum('price');

  assertEquals(total, 4.25, 'Sum calculated correctly');
}

// Test 17: Sum with mixed types
console.log('\n--- Test 17: Sum with Mixed Types ---');
{
  const csv = `name,value
John,100
Jane,not_a_number
Bob,50`;

  const result = parseCSV(csv);
  const total = result.sum('value');

  assertEquals(total, 150, 'Sum ignores non-numeric values');
}

// Test 18: Average aggregation
console.log('\n--- Test 18: Average Aggregation ---');
{
  const csv = `product,price
Apple,10
Banana,20
Orange,30`;

  const result = parseCSV(csv);
  const avg = result.average('price');

  assertEquals(avg, 20, 'Average calculated correctly');
}

// Test 19: Average with no numeric values
console.log('\n--- Test 19: Average with No Numeric Values ---');
{
  const csv = `name,text
John,hello
Jane,world`;

  const result = parseCSV(csv);
  const avg = result.average('text');

  assertEquals(avg, 0, 'Average returns 0 for no numeric values');
}

// Test 20: Count aggregation
console.log('\n--- Test 20: Count Aggregation ---');
{
  const csv = `name,age
John,30
Jane,25
Bob,35`;

  const result = parseCSV(csv);
  const count = result.count();

  assertEquals(count, 3, 'Count returns correct number');
}

// Test 21: GroupBy aggregation
console.log('\n--- Test 21: GroupBy Aggregation ---');
{
  const csv = `department,employee,salary
Sales,John,50000
Engineering,Jane,60000
Sales,Bob,55000
Engineering,Alice,65000`;

  const result = parseCSV(csv);
  const grouped = result.groupBy('department');

  assertEquals(grouped.size, 2, 'GroupBy creates correct number of groups');
  assertEquals(grouped.get('Sales').length, 2, 'Sales group has 2 employees');
  assertEquals(grouped.get('Engineering').length, 2, 'Engineering group has 2 employees');
}

// Test 22: GroupBy with null values
console.log('\n--- Test 22: GroupBy with Null Values ---');
{
  const csv = `category,value
A,100
,200
A,150`;

  const result = parseCSV(csv);
  const grouped = result.groupBy('category');

  assertEquals(grouped.size, 2, 'GroupBy handles null values');
  assert(grouped.has(null), 'Null is a valid group key');
  assertEquals(grouped.get(null).length, 1, 'Null group has correct size');
}

// Test 23: GroupBy with numbers
console.log('\n--- Test 23: GroupBy with Numbers ---');
{
  const csv = `id,name
1,John
2,Jane
1,Bob`;

  const result = parseCSV(csv);
  const grouped = result.groupBy('id');

  assertEquals(grouped.size, 2, 'GroupBy works with numeric values');
  assertEquals(grouped.get(1).length, 2, 'Group 1 has correct size');
  assertEquals(grouped.get(2).length, 1, 'Group 2 has correct size');
}

// Test 24: Invalid column error for aggregation
console.log('\n--- Test 24: Invalid Column Error ---');
{
  const csv = `name,age
John,30`;

  const result = parseCSV(csv);

  assertThrows(
    () => result.sum('invalid_column'),
    'Sum throws error for invalid column'
  );
  assertThrows(
    () => result.average('invalid_column'),
    'Average throws error for invalid column'
  );
  assertThrows(
    () => result.groupBy('invalid_column'),
    'GroupBy throws error for invalid column'
  );
}

// Test 25: Empty input
console.log('\n--- Test 25: Empty Input ---');
{
  const result = parseCSV('');

  assertEquals(result.rows.length, 0, 'Empty input returns empty rows');
  assertEquals(result.headers.length, 0, 'Empty input returns empty headers');
  assertEquals(result.errors.length, 0, 'No errors for empty input');
}

// Test 26: Only headers
console.log('\n--- Test 26: Only Headers ---');
{
  const csv = `name,age,city`;

  const result = parseCSV(csv);

  assertEquals(result.headers, ['name', 'age', 'city'], 'Headers parsed');
  assertEquals(result.rows.length, 0, 'No data rows');
}

// Test 27: Single column
console.log('\n--- Test 27: Single Column ---');
{
  const csv = `names
John
Jane
Bob`;

  const result = parseCSV(csv);

  assertEquals(result.headers, ['names'], 'Single header parsed');
  assertEquals(result.count(), 3, 'All rows parsed');
  assertEquals(result.rows[0], { names: 'John' }, 'Single column data correct');
}

// Test 28: Single row
console.log('\n--- Test 28: Single Row ---');
{
  const csv = `name,age,city
John,30,New York`;

  const result = parseCSV(csv);

  assertEquals(result.headers, ['name', 'age', 'city'], 'Headers parsed');
  assertEquals(result.count(), 1, 'Single row parsed');
  assertEquals(result.rows[0], { name: 'John', age: 30, city: 'New York' }, 'Row data correct');
}

// Test 29: Very long field
console.log('\n--- Test 29: Very Long Field ---');
{
  const longText = 'a'.repeat(10000);
  const csv = `name,description
John,"${longText}"`;

  const result = parseCSV(csv);

  assertEquals(result.rows[0].description.length, 10000, 'Very long field parsed');
  assertEquals(result.rows[0].description, longText, 'Long field content correct');
}

// Test 30: Mixed quotes and delimiters in quoted field
console.log('\n--- Test 30: Mixed Quotes and Delimiters ---');
{
  const csv = `name,data
John,"value1,value2,""special"""
Jane,"simple"`;

  const result = parseCSV(csv);

  assertEquals(
    result.rows[0].data,
    'value1,value2,"special"',
    'Complex quoted field parsed correctly'
  );
  assertEquals(result.rows[1].data, 'simple', 'Simple quoted field parsed');
}

// Test 31: Whitespace handling
console.log('\n--- Test 31: Whitespace Handling ---');
{
  const csv = `name,age
  John  ,  30  
Jane,25`;

  const result = parseCSV(csv);

  assertEquals(result.rows[0].name, 'John', 'Surrounding whitespace trimmed from name');
  assertEquals(result.rows[0].age, 30, 'Surrounding whitespace trimmed from number');
  assertEquals(result.rows[1].name, 'Jane', 'Name without extra spaces');
}

// Test 32: Chained filtering
console.log('\n--- Test 32: Chained Filtering ---');
{
  const csv = `name,age,city
John,30,New York
Jane,25,New York
Bob,35,Los Angeles
Alice,28,New York`;

  const result = parseCSV(csv);
  const filtered = result
    .filter((row) => row.city === 'New York')
    .filter((row) => row.age >= 28);

  assertEquals(filtered.count(), 2, 'Chained filter works correctly');
  assertEquals(
    filtered.rows.map((r) => r.name).sort(),
    ['Alice', 'John'],
    'Correct rows after chaining'
  );
}

// Test 33: Filter preserves headers and errors
console.log('\n--- Test 33: Filter Preserves Headers ---');
{
  const csv = `name,age,city
John,30,New York
Jane,25,Los Angeles`;

  const result = parseCSV(csv);
  const filtered = result.filter((row) => row.age > 26);

  assertEquals(filtered.headers, result.headers, 'Headers preserved after filter');
  assertEquals(filtered.errors, result.errors, 'Errors preserved after filter');
}

// Test 34: Sum after filter
console.log('\n--- Test 34: Aggregation After Filter ---');
{
  const csv = `product,price,category
Apple,1.50,fruit
Banana,0.75,fruit
Carrot,0.50,vegetable`;

  const result = parseCSV(csv);
  const fruitOnly = result.filter((row) => row.category === 'fruit');
  const total = fruitOnly.sum('price');

  assertEquals(total, 2.25, 'Sum after filter calculated correctly');
}

// Test 35: Multiple delimiters in quoted field
console.log('\n--- Test 35: Multiple Delimiters in Quoted Field ---');
{
  const csv = `id,path
1,"C:\\Users\\Documents\\file.txt"
2,"D:\\Data\\backup"`;

  const result = parseCSV(csv);

  assertEquals(
    result.rows[0].path,
    'C:\\Users\\Documents\\file.txt',
    'Backslashes in quoted field preserved'
  );
}

// Test 36: Quote at start of unquoted field
console.log('\n--- Test 36: Quote Handling ---');
{
  const csv = `name,description
John,"value"
Jane,plain text`;

  const result = parseCSV(csv);

  assertEquals(result.rows[0].description, 'value', 'Quoted value parsed');
  assertEquals(result.rows[1].description, 'plain text', 'Unquoted value parsed');
}

// Test 37: Headers with spaces
console.log('\n--- Test 37: Headers with Spaces ---');
{
  const csv = `first name, last name, age
John, Doe, 30
Jane, Smith, 25`;

  const result = parseCSV(csv);

  assertEquals(result.headers[0], 'first name', 'Header with leading space trimmed');
  assertEquals(result.headers[1], 'last name', 'Header with spaces');
  assertEquals(result.count(), 2, 'Data rows parsed');
}

// Test 38: Numeric strings vs numbers
console.log('\n--- Test 38: Numeric Coercion Edge Cases ---');
{
  const csv = `id,code,value
001,A123,+50
002,B456,1.0e2`;

  const result = parseCSV(csv);

  assertEquals(result.rows[0].id, 1, 'Leading zeros coerced to number');
  assertEquals(result.rows[0].code, 'A123', 'Alphanumeric stays string');
  assertEquals(result.rows[0].value, 50, 'Plus sign coerced to number');
  assertEquals(result.rows[1].value, 100, 'Scientific notation coerced');
}

// Test 39: Complex CSV from real world
console.log('\n--- Test 39: Complex Real-World CSV ---');
{
  const csv = `id,name,email,salary,department,notes
1,"Smith, John",john@example.com,50000,Sales,"Excellent ""performer"""
2,"Doe, Jane",jane@example.com,60000,Engineering,"Team lead, ""very skilled"""
3,"Johnson, Bob",bob@example.com,,Management,null`;

  const result = parseCSV(csv);

  assertEquals(result.count(), 3, 'All rows parsed');
  assertEquals(result.rows[0].name, 'Smith, John', 'Name with comma in quotes');
  assertEquals(result.rows[0].salary, 50000, 'Salary coerced to number');
  assertEquals(
    result.rows[0].notes,
    'Excellent "performer"',
    'Escaped quotes handled correctly'
  );
  assertEquals(result.rows[2].salary, null, 'Empty salary becomes null');
  assertEquals(result.rows[2].notes, null, 'Null string becomes null');
}

// Test 40: Filter returns CSVResult with methods
console.log('\n--- Test 40: Filtered Result Has Methods ---');
{
