/**
 * CSV Parser Library
 * Comprehensive CSV parsing with type coercion, filtering, and aggregation
 */

// Type definitions
export interface CSVOptions {
  delimiter?: string;
  quote?: string;
  lineSeparator?: string;
}

export interface ParseError {
  row: number;
  message: string;
}

export interface CSVResult {
  rows: Record<string, any>[];
  headers: string[];
  errors: ParseError[];
  filter(predicate: (row: Record<string, any>, index: number) => boolean): CSVResult;
  sum(column: string): number;
  average(column: string): number;
  count(): number;
  groupBy(column: string): Map<any, Record<string, any>[]>;
}

/**
 * Parse a CSV string into structured data
 */
export function parseCSV(input: string, options?: CSVOptions): CSVResult {
  const delimiter = options?.delimiter ?? ',';
  const quote = options?.quote ?? '"';
  const lineSeparator = options?.lineSeparator ?? '\n';

  const errors: ParseError[] = [];
  const rows: Record<string, any>[] = [];
  let headers: string[] = [];

  // Handle empty input
  if (!input || input.trim() === '') {
    return createCSVResult([], [], errors);
  }

  // Split by line separator
  const lines = input.split(lineSeparator);

  for (let lineIndex = 0; lineIndex < lines.length; lineIndex++) {
    const line = lines[lineIndex];

    // Skip empty lines
    if (!line.trim()) {
      continue;
    }

    try {
      const fields = parseFields(line, delimiter, quote);

      if (lineIndex === 0 || headers.length === 0) {
        // First non-empty line is headers
        headers = fields.map((field) => coerceType(field) as string);
      } else {
        // Parse data row
        if (fields.length !== headers.length) {
          errors.push({
            row: lineIndex + 1,
            message: `Expected ${headers.length} columns but got ${fields.length}`,
          });
          continue;
        }

        const row: Record<string, any> = {};
        for (let i = 0; i < headers.length; i++) {
          row[headers[i]] = coerceType(fields[i]);
        }
        rows.push(row);
      }
    } catch (error) {
      errors.push({
        row: lineIndex + 1,
        message: error instanceof Error ? error.message : 'Unknown parse error',
      });
    }
  }

  return createCSVResult(rows, headers, errors);
}

/**
 * Parse fields from a single CSV line
 */
function parseFields(line: string, delimiter: string, quote: string): string[] {
  const fields: string[] = [];
  let currentField = '';
  let inQuotes = false;
  let i = 0;

  while (i < line.length) {
    const char = line[i];
    const nextChar = line[i + 1];

    // Check for quote character
    if (char === quote) {
      if (inQuotes) {
        // We're inside quotes - check if this is an escaped quote
        if (nextChar === quote) {
          // Escaped quote - add single quote and skip both characters
          currentField += quote;
          i += 2;
          continue;
        } else {
          // End of quoted field
          inQuotes = false;
          i++;
          continue;
        }
      } else if (currentField === '') {
        // Start of quoted field
        inQuotes = true;
        i++;
        continue;
      } else {
        // Quote in the middle of unquoted field - treat as literal
        currentField += char;
        i++;
        continue;
      }
    }

    // Check for delimiter
    if (char === delimiter && !inQuotes) {
      fields.push(currentField);
      currentField = '';
      i++;
      continue;
    }

    // Regular character
    currentField += char;
    i++;
  }

  // Add the last field
  fields.push(currentField);

  return fields;
}

/**
 * Coerce a string value to its appropriate type
 */
function coerceType(value: string): string | number | boolean | null {
  // Trim whitespace
  const trimmed = value.trim();

  // Check for null values
  if (trimmed === '' || trimmed === 'null' || trimmed === 'NULL') {
    return null;
  }

  // Check for boolean values
  if (trimmed.toLowerCase() === 'true') {
    return true;
  }
  if (trimmed.toLowerCase() === 'false') {
    return false;
  }

  // Check for numeric values
  if (/^-?\d+\.?\d*$/.test(trimmed)) {
    const num = Number(trimmed);
    if (!isNaN(num)) {
      return num;
    }
  }

  // Return as string
  return trimmed;
}

/**
 * Create a CSVResult object with methods
 */
function createCSVResult(
  rows: Record<string, any>[],
  headers: string[],
  errors: ParseError[]
): CSVResult {
  return {
    rows,
    headers,
    errors,

    filter(predicate: (row: Record<string, any>, index: number) => boolean): CSVResult {
      const filtered = rows.filter(predicate);
      return createCSVResult(filtered, headers, errors);
    },

    sum(column: string): number {
      if (!headers.includes(column)) {
        throw new Error(`Column "${column}" not found in headers`);
      }

      let total = 0;
      for (const row of rows) {
        const value = row[column];
        if (typeof value === 'number') {
          total += value;
        }
      }
      return total;
    },

    average(column: string): number {
      if (!headers.includes(column)) {
        throw new Error(`Column "${column}" not found in headers`);
      }

      let total = 0;
      let count = 0;
      for (const row of rows) {
        const value = row[column];
        if (typeof value === 'number') {
          total += value;
          count++;
        }
      }

      if (count === 0) {
        return 0;
      }
      return total / count;
    },

    count(): number {
      return rows.length;
    },

    groupBy(column: string): Map<any, Record<string, any>[]> {
      if (!headers.includes(column)) {
        throw new Error(`Column "${column}" not found in headers`);
      }

      const groups = new Map<any, Record<string, any>[]>();
      for (const row of rows) {
        const key = row[column];
        if (!groups.has(key)) {
          groups.set(key, []);
        }
        groups.get(key)!.push(row);
      }
      return groups;
    },
  };
}

