import { parseCSV, CSVResult } from './csv-parser';

// Test utilities
let testsPassed = 0;
let testsFailed = 0;

function assert(condition: boolean, message: string): void {
  if (!condition) {
    console.error(`вқҢ FAILED: ${message}`);
    testsFailed++;
    throw new Error(`Assertion failed: ${message}`);
  }
  console.log(`вң“ ${message}`);
  testsPassed++;
}

function assertEquals<T>(actual: T, expected: T, message: string): void {
  if (JSON.stringify(actual) !== JSON.stringify(expected)) {
    console.error(
      `вқҢ FAILED: ${message}\n   Expected: ${JSON.stringify(expected)}\n   Actual: ${JSON.stringify(actual)}`
    );
    testsFailed++;
    throw new Error(`Assertion failed: ${message}`);
  }
  console.log(`вң“ ${message}`);
  testsPassed++;
}

function assertThrows(fn: () => void, message: string): void {
  try {
    fn();
    console.error(`вқҢ FAILED: ${message} - Expected exception to be thrown`);
    testsFailed++;
    throw new Error(`Assertion failed: ${message}`);
  } catch (error) {
    console.log(`вң“ ${message}`);
    testsPassed++;
  }
}

// Tests

