# CSV Parser Library - Examples

## Quick Start

```typescript
import { parseCSV } from './csv-parser';

const csv = `name,age,city
John,30,New York
Jane,25,Los Angeles`;

const result = parseCSV(csv);
console.log(result.rows);  // Parsed data
console.log(result.headers);  // Column names
```

## Example 1: Basic CSV Parsing

```typescript
const csv = `name,email,phone
Alice,alice@example.com,555-1234
Bob,bob@example.com,555-5678
Charlie,charlie@example.com,555-9999`;

const result = parseCSV(csv);

console.log(`Parsed ${result.count()} contacts`);
result.rows.forEach(contact => {
  console.log(`${contact.name} (${contact.email})`);
});
```

## Example 2: Quoted Fields with Commas

```typescript
const csv = `id,name,address
1,"Smith, John","123 Main St, New York, NY"
2,"Doe, Jane","456 Oak Ave, Los Angeles, CA"`;

const result = parseCSV(csv);
console.log(result.rows[0].name);     // "Smith, John"
console.log(result.rows[0].address);  // "123 Main St, New York, NY"
```

## Example 3: Escaped Quotes

```typescript
const csv = `id,review
1,"Product was ""amazing"" - highly recommended!"
2,"Great item! I ""love"" it!"`;

const result = parseCSV(csv);
console.log(result.rows[0].review);  // Product was "amazing" - highly recommended!
console.log(result.rows[1].review);  // Great item! I "love" it!
```

## Example 4: Type Coercion

```typescript
const csv = `item,quantity,price,in_stock,last_reviewed
Apple,50,1.50,true,2024-01-15
Banana,120,0.75,true,null
Orange,30,-0.50,false,NULL
Grape,,2.99,TRUE,`;

const result = parseCSV(csv);

const row1 = result.rows[0];
console.log(row1.quantity);      // 50 (number)
console.log(row1.price);         // 1.50 (number)
console.log(row1.in_stock);      // true (boolean)
console.log(row1.last_reviewed); // "2024-01-15" (string - not parsed as date)

const row2 = result.rows[1];
console.log(row2.quantity);      // null (empty becomes null)
console.log(row2.last_reviewed); // null (null string)

const row3 = result.rows[2];
console.log(row3.in_stock);      // false (FALSE coerced to boolean)
console.log(row3.price);         // -0.5 (negative number)
```

## Example 5: Custom Delimiter

```typescript
// Tab-separated values
const tsv = `name\tage\tcity
John\t30\tNew York
Jane\t25\tLos Angeles`;

const result = parseCSV(tsv, { delimiter: '\t' });
console.log(result.headers);  // ['name', 'age', 'city']
console.log(result.rows[0].age);  // 30

// Pipe-separated values
const psv = `name|department|salary
Alice|Engineering|80000
Bob|Sales|70000`;

const result2 = parseCSV(psv, { delimiter: '|' });
```

## Example 6: Custom Quote Character

```typescript
const csv = `name,description
John,'Contains, comma'
Jane,'Single "quotes" inside'`;

const result = parseCSV(csv, { quote: "'" });
console.log(result.rows[0].description);  // Contains, comma
```

## Example 7: Filtering

```typescript
const csv = `name,age,department,salary
Alice,32,Engineering,95000
Bob,28,Sales,70000
Charlie,35,Engineering,100000
Diana,26,Sales,65000
Eve,40,Management,110000`;

const result = parseCSV(csv);

// Simple filter
const engineers = result.filter(row => row.department === 'Engineering');
console.log(`Engineers: ${engineers.count()}`);

// Complex filter
const highEarners = result.filter(row => row.salary > 80000);
console.log(`High earners: ${highEarners.count()}`);

// Chained filters
const seniorEngineers = result
  .filter(row => row.department === 'Engineering')
  .filter(row => row.age >= 35);
console.log(`Senior engineers: ${seniorEngineers.count()}`);
```

## Example 8: Aggregation - Sum and Average

```typescript
const csv = `product,quantity,price,discount
Widget,100,25.00,0
Gadget,50,50.00,5
Doohickey,75,15.00,10`;

const result = parseCSV(csv);

const totalQuantity = result.sum('quantity');        // 225
const avgPrice = result.average('price');            // 30.00
const totalDiscount = result.sum('discount');        // 15

console.log(`Total quantity: ${totalQuantity}`);
console.log(`Average price: $${avgPrice.toFixed(2)}`);
console.log(`Total discount: ${totalDiscount}`);

// Filter then aggregate
const highValue = result
  .filter(row => row.price > 20)
  .sum('quantity');
console.log(`Quantity of high-value items: ${highValue}`);
```

## Example 9: GroupBy Aggregation

```typescript
const csv = `department,employee,salary
Sales,John,50000
Engineering,Jane,70000
Sales,Bob,55000
Engineering,Alice,75000
Marketing,Charlie,60000`;

const result = parseCSV(csv);

// Group by department
const byDept = result.groupBy('department');

for (const [dept, employees] of byDept) {
  const total = employees.reduce((sum, emp) => sum + emp.salary, 0);
  const avg = total / employees.length;
  console.log(`${dept}: ${employees.length} employees, avg salary $${avg.toFixed(0)}`);
}

// Output:
// Sales: 2 employees, avg salary $52500
// Engineering: 2 employees, avg salary $72500
// Marketing: 1 employees, avg salary $60000
```

## Example 10: Complex Real-World Example

```typescript
const csv = `id,name,email,department,salary,hire_date,active
1,"Johnson, Mark",mark.johnson@corp.com,Engineering,85000,2018-03-15,true
2,"Smith, Sarah",sarah.smith@corp.com,Sales,70000,2019-06-01,true
3,"Williams, Robert",r.williams@corp.com,Engineering,90000,2017-01-10,true
4,"Brown, Jennifer",j.brown@corp.com,Marketing,65000,2020-11-20,true
5,"Davis, Michael",m.davis@corp.com,Sales,72000,2019-08-15,false`;

const result = parseCSV(csv);

// Check parsing
console.log(`Parsed ${result.count()} employees`);
if (result.errors.length > 0) {
  console.warn(`Errors: ${result.errors.length}`);
}

// Analysis
console.log('\n=== Department Summary ===');
const byDept = result.groupBy('department');
for (const [dept, employees] of byDept) {
  const active = employees.filter(e => e.active).length;
  const salaries = employees.map(e => e.salary);
  const avgSalary = salaries.reduce((a, b) => a + b, 0) / salaries.length;
  const totalSalary = salaries.reduce((a, b) => a + b, 0);

  console.log(`\n${dept}:`);
  console.log(`  Employees: ${employees.length} (${active} active)`);
  console.log(`  Total salary: $${totalSalary.toLocaleString()}`);
  console.log(`  Average salary: $${avgSalary.toFixed(0).toLocaleString()}`);
}

// High earners
console.log('\n=== High Earners (>$80k) ===');
const highEarners = result.filter(row => row.salary > 80000);
highEarners.rows.forEach(emp => {
  console.log(`${emp.name} - $${emp.salary.toLocaleString()} (${emp.department})`);
});

// Average by department
console.log('\n=== Average Salary by Department ===');
for (const [dept, employees] of byDept) {
  const avg = employees.reduce((sum, e) => sum + e.salary, 0) / employees.length;
  console.log(`${dept}: $${avg.toFixed(0)}`);
}
```

## Example 11: Error Handling

```typescript
const csv = `id,name,age
1,John,30
2,Jane
3,Bob,25,extra_column`;

const result = parseCSV(csv);

console.log(`Successfully parsed: ${result.count()} rows`);

if (result.errors.length > 0) {
  console.log(`\nParsing errors:`);
  result.errors.forEach(error => {
    console.log(`  Row ${error.row}: ${error.message}`);
  });
}

// Output:
// Successfully parsed: 2 rows
// 
// Parsing errors:
//   Row 3: Expected 3 columns but got 2
//   Row 4: Expected 3 columns but got 4
```

## Example 12: Data Validation Pipeline

```typescript
const csv = loadCSVFile('users.csv');
const result = parseCSV(csv);

// Step 1: Check for parsing errors
if (result.errors.length > 0) {
  console.error(`${result.errors.length} rows have parsing errors`);
  result.errors.forEach(e => console.error(`  Row ${e.row}: ${e.message}`));
}

// Step 2: Validate required fields
const validRows = result.filter(row => 
  row.email && 
  row.name && 
  row.age !== null
);

console.log(`${validRows.count()} valid rows out of ${result.count()}`);

// Step 3: Filter by age range
const adults = validRows.filter(row => row.age >= 18 && row.age <= 120);
console.log(`${adults.count()} valid adults`);

// Step 4: Group by domain
const byDomain = adults.groupBy(row => row.email.split('@')[1]);
console.log(`Users across ${byDomain.size} email domains`);
```

## Example 13: Data Transformation

```typescript
const csv = `first_name,last_name,birth_year
John,Doe,1990
Jane,Smith,1985`;

const result = parseCSV(csv);

// Transform the data
const transformed = result.rows.map(row => ({
  ...row,
  full_name: `${row.first_name} ${row.last_name}`,
  age: new Date().getFullYear() - row.birth_year
}));

transformed.forEach(person => {
  console.log(`${person.full_name} is ${person.age} years old`);
});
```

## Example 14: Large Dataset Performance

```typescript
// For large CSV files, you can process in chunks
const csv = readLargeCSVFile('data.csv');  // Could be MB in size
const result = parseCSV(csv);

console.log(`Processing ${result.count()} rows...`);

// Process in batches
const batchSize = 100;
for (let i = 0; i < result.rows.length; i += batchSize) {
  const batch = result.rows.slice(i, i + batchSize);
  processBatch(batch);
  console.log(`Processed ${Math.min(i + batchSize, result.count())} rows`);
}
```

## Example 15: Export to Different Format

```typescript
const csv = `name,age,email
Alice,30,alice@example.com
Bob,25,bob@example.com`;

const result = parseCSV(csv);

// Export to JSON
const json = JSON.stringify(result.rows, null, 2);
console.log(json);

// Export to TSV
const tsv = [
  result.headers.join('\t'),
  ...result.rows.map(row => 
    result.headers.map(h => row[h]).join('\t')
  )
].join('\n');
console.log(tsv);

// Export to HTML table
const html = `
<table>
  <thead>
    <tr>${result.headers.map(h => `<th>${h}</th>`).join('')}</tr>
  </thead>
  <tbody>
    ${result.rows.map(row => 
      `<tr>${result.headers.map(h => `<td>${row[h]}</td>`).join('')}</tr>`
    ).join('')}
  </tbody>
</table>`;
console.log(html);
```

# Quick Start Guide

## Installation

```bash
# No npm packages required for the library itself
# But if you want to run tests, install TypeScript:
npm install
```

## Basic Usage (5 minutes)

### 1. Import the library
```typescript
import { parseCSV } from './csv-parser';
```

### 2. Parse a CSV string
```typescript
const csv = `name,age,city
John,30,New York
Jane,25,Los Angeles`;

const result = parseCSV(csv);
```

### 3. Access the data
```typescript
// Get the parsed rows
console.log(result.rows);
// [
//   { name: 'John', age: 30, city: 'New York' },
//   { name: 'Jane', age: 25, city: 'Los Angeles' }
// ]

// Get the column headers
console.log(result.headers);
// ['name', 'age', 'city']

// Count the rows
console.log(result.count());
// 2

// Check for errors
console.log(result.errors);
// []
```

## Common Operations

### Filter rows
```typescript
const adults = result.filter(row => row.age >= 18);
console.log(adults.count());  // 2
```

### Aggregate data
```typescript
const totalAge = result.sum('age');        // 55
const avgAge = result.average('age');      // 27.5
const count = result.count();              // 2
```

### Group by column
```typescript
const byCity = result.groupBy('city');
for (const [city, rows] of byCity) {
  console.log(`${city}: ${rows.length} people`);
}
// New York: 1 people
// Los Angeles: 1 people
```

## Type Coercion (Automatic)

```typescript
const csv = `name,age,active,score
Alice,30,true,95.5
Bob,25,false,null`;

const result = parseCSV(csv);

// age: number
// active: boolean
// score: number (or null)
console.log(typeof result.rows[0].age);     // 'number'
console.log(typeof result.rows[0].active);  // 'boolean'
console.log(result.rows[1].score);          // null
```

## Quoted Fields with Commas

```typescript
const csv = `name,address
John,"123 Main St, New York"
Jane,"456 Oak Ave, Los Angeles"`;

const result = parseCSV(csv);
console.log(result.rows[0].address);
// "123 Main St, New York"
```

## Custom Delimiters

```typescript
// Tab-separated values
const tsv = `name\tage\tcity
John\t30\tNew York`;

const result = parseCSV(tsv, { delimiter: '\t' });

// Pipe-separated values
const psv = `name|age|city
John|30|New York`;

const result2 = parseCSV(psv, { delimiter: '|' });
```

## Chaining Operations

```typescript
const result = parseCSV(csv)
  .filter(row => row.age >= 25)
  .filter(row => row.city === 'New York');

console.log(result.count());

const total = result.sum('salary');
```

## Error Handling

```typescript
const csv = `name,age,city
John,30
Jane,25,LA,extra`;

const result = parseCSV(csv);

if (result.errors.length > 0) {
  console.log('Parsing errors:');
  result.errors.forEach(err => {
    console.log(`Row ${err.row}: ${err.message}`);
  });
}

// Successfully parsed rows
console.log(`Valid rows: ${result.count()}`);
```

## Real-World Example

```typescript
const salesData = parseCSV(`
name,department,salary,active
Alice,Engineering,95000,true
Bob,Sales,70000,true
Charlie,Engineering,85000,false
Diana,Marketing,65000,true
`);

// Get active employees only
const active = salesData.filter(row => row.active);

// Group by department
const byDept = active.groupBy('department');

// Analyze each department
for (const [dept, employees] of byDept) {
  const avg = employees.reduce((sum, e) => sum + e.salary, 0) / employees.length;
  console.log(`${dept}: ${employees.length} active, avg salary $${Math.round(avg)}`);
}
// Engineering: 1 active, avg salary $95000
// Sales: 1 active, avg salary $70000
// Marketing: 1 active, avg salary $65000
```

## Running Tests

```bash
# Install dependencies
npm install

# Run the comprehensive test suite
